/// Fold (icmp ult (add A, B), A) | (icmp ult (add A, B), B) -> icmp ult (add A, B), A
/// Both conditions detect unsigned overflow and are equivalent.
static Value *foldICmpUltOfAddWithOperands(ICmpInst *LHS, ICmpInst *RHS,
                                           InstCombiner::BuilderTy &Builder) {
  Value *LHS0 = LHS->getOperand(0), *LHS1 = LHS->getOperand(1);
  Value *RHS0 = RHS->getOperand(0), *RHS1 = RHS->getOperand(1);

  // Both must be icmp ult
  if (LHS->getPredicate() != ICmpInst::ICMP_ULT ||
      RHS->getPredicate() != ICmpInst::ICMP_ULT)
    return nullptr;

  // Find the add instruction - it could be on LHS or RHS of each icmp
  BinaryOperator *AddL = dyn_cast<BinaryOperator>(LHS0);
  BinaryOperator *AddR = dyn_cast<BinaryOperator>(RHS0);
  BinaryOperator *Add = nullptr;
  Value *OtherL = nullptr, *OtherR = nullptr;

  if (AddL && AddL->getOpcode() == Instruction::Add) {
    Add = AddL;
    OtherL = LHS1;
  } else if (AddR && AddR->getOpcode() == Instruction::Add) {
    Add = AddR;
    OtherL = RHS1;
  } else {
    return nullptr;
  }

  // Check the other icmp also uses the same add
  BinaryOperator *Add2 = dyn_cast<BinaryOperator>(LHS == AddL ? RHS0 : LHS0);
  if (!Add2 || Add2 != Add)
    return nullptr;
  OtherR = LHS == AddL ? RHS1 : LHS1;

  Value *AddOp0 = Add->getOperand(0);
  Value *AddOp1 = Add->getOperand(1);

  // Check that the other operands of the icmps are the add operands
  // Pattern: (icmp ult (add A, B), A) | (icmp ult (add A, B), B)
  bool Match1 = (OtherL == AddOp0 && OtherR == AddOp1) ||
                (OtherL == AddOp1 && OtherR == AddOp0);
  if (!Match1)
    return nullptr;

  // Simplify to just one of the comparisons
  return LHS;
}
